import java.nio.charset.Charset;
import java.nio.charset.IllegalCharsetNameException;

public class CharsetCheck {
    public static void main(String[] args) {
        check("utf-8");
        check("UTF-8");
        check("Unknown");
        check("Unsupported");
        check("");
        check("   ");
    }

    private static void check(String name) {
        try {
            boolean supported = Charset.isSupported(name);
            System.out.println("'" + name + "': supported=" + supported);
        } catch (IllegalCharsetNameException e) {
            System.out.println("'" + name + "': IllegalCharsetNameException");
        } catch (IllegalArgumentException e) {
            System.out.println("'" + name + "': IllegalArgumentException");
        } catch (Exception e) {
            System.out.println("'" + name + "': " + e.getClass().getSimpleName());
        }
    }
}
